-- ═══════════════════════════════════════════
-- CHAPTERS 11 – 20
-- ═══════════════════════════════════════════

-- ═══ Joshua Chapter 11 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Joshua', 11, 'kids', 1, 'Which city did Joshua burn in the northern campaign?', 'Jericho', 'Hazor', 'Ai', 'Gibeon', 'a', 'Joshua 11:11 — "And they smote all the souls that were therein with the edge of the sword... and he burnt Hazor with fire."'),
('Joshua', 11, 'kids', 2, 'Where did Joshua defeat the northern kings'' armies?', 'The Jordan River', 'The waters of Merom', 'The Sea of Galilee', 'The Dead Sea', 'a', 'Joshua 11:7 — "So Joshua came, and all the people of war with him, against them by the waters of Merom suddenly."'),
('Joshua', 11, 'kids', 3, 'Who were the tall, giant people that Joshua destroyed in the hill country?', 'The Philistines', 'The Amalekites', 'The Anakim', 'The Moabites', 'a', 'Joshua 11:21 — "And at that time came Joshua, and cut off the Anakim from the mountains."'),
-- Teens
('Joshua', 11, 'teens', 1, 'Who was the king that organized the great northern coalition against Israel?', 'Og of Bashan', 'Jabin king of Hazor', 'Adoni-zedek of Jerusalem', 'Hoham king of Hebron', 'a', 'Joshua 11:1 — "And it came to pass, when Jabin king of Hazor had heard those things, that he sent to Jobab king of Madon."'),
('Joshua', 11, 'teens', 2, 'What did God tell Joshua to do to the enemies'' horses and chariots?', 'Capture them for Israel', 'Hough the horses and burn the chariots', 'Drive them into the sea', 'Give them to the Levites', 'a', 'Joshua 11:6 — "Thou shalt hough their horses, and burn their chariots with fire."'),
('Joshua', 11, 'teens', 3, 'How long did Joshua make war with all those kings?', 'One year', 'Three years', 'A long time', 'Forty years', 'a', 'Joshua 11:18 — "Joshua made war a long time with all those kings."'),
('Joshua', 11, 'teens', 4, 'Where were the surviving Anakim found after Joshua destroyed them in the hill country?', 'In Egypt and Moab', 'In Gaza, Gath, and Ashdod', 'In Jericho and Ai', 'In Gilgal and Shiloh', 'a', 'Joshua 11:22 — "There was none of the Anakims left in the land of the children of Israel: only in Gaza, in Gath, and in Ashdod, there remained."'),
('Joshua', 11, 'teens', 5, 'What was the spiritual reason the Canaanite cities hardened their hearts to fight Israel?', 'They were deceived by false prophets', 'It was of the LORD to destroy them', 'They did not know Israel was coming', 'Joshua refused to make peace with them', 'a', 'Joshua 11:20 — "For it was of the LORD to harden their hearts, that they should come against Israel in battle, that he might destroy them utterly."'),
-- Adults
('Joshua', 11, 'adults', 1, 'What was notable about the size of the northern coalition army described in Joshua 11:4?', 'It numbered exactly 600,000', 'It was as the sand of the sea in multitude with horses and chariots', 'It had thirty-one kings with their armies', 'It was larger than Egypt''s army', 'a', 'Joshua 11:4 — "And they went out, they and all their hosts with them, much people, even as the sand that is upon the sea shore in multitude, with horses and chariots very many."'),
('Joshua', 11, 'adults', 2, 'What command did God repeat to Joshua before the battle at Merom, echoing earlier promises?', 'Be not afraid of them', 'The land will be yours forever', 'March around them seven times', 'Send the priests out first', 'a', 'Joshua 11:6 — "And the LORD said unto Joshua, Be not afraid because of them: for to morrow about this time will I deliver them up all slain before Israel."'),
('Joshua', 11, 'adults', 3, 'Where did Joshua chase the fleeing northern coalition after defeating them at Merom?', 'Unto Sidon and Misrephoth-maim and Mizpeh', 'Into the wilderness of Judah', 'Across the Jordan River', 'Into the land of Egypt', 'a', 'Joshua 11:8 — "The LORD delivered them into the hand of Israel... and they smote them, until they left them none remaining. And Joshua... chased them unto great Zidon, and unto Misrephoth-maim."'),
('Joshua', 11, 'adults', 4, 'What single city of the northern cities that stood on their mounds did Joshua specifically burn with fire?', 'Megiddo', 'Hazor', 'Kedesh', 'Laish', 'a', 'Joshua 11:13 — "But as for the cities that stood still in their strength, Israel burned none of them, save Hazor only; that did Joshua burn."'),
('Joshua', 11, 'adults', 5, 'Which land did Joshua take during the northern campaign that extended from the mountain to Baal-gad under Mount Hermon?', 'All the land from Goshen to Gibeon', 'From the mount Halak unto mount Hermon', 'From the river Arnon to the Jabbok', 'From Kadesh-barnea to Gaza', 'a', 'Joshua 11:17 — "Even from the mount Halak, that goeth up to Seir, even unto Baalgad in the valley of Lebanon under mount Hermon."'),
('Joshua', 11, 'adults', 6, 'How does Joshua 11:15 connect Joshua''s obedience to Moses''s commands?', 'Joshua exceeded Moses''s instructions in zeal', 'As the LORD commanded Moses, so did Moses command Joshua, and so did Joshua', 'Joshua consulted the priests rather than Moses''s writings', 'Joshua added his own statutes to Moses''s commands', 'a', 'Joshua 11:15 — "As the LORD commanded Moses his servant, so did Moses command Joshua, and so did Joshua; he left nothing undone of all that the LORD commanded Moses."'),
('Joshua', 11, 'adults', 7, 'What key theological statement ends the summary of the whole Canaanite conquest in Joshua 11:23?', 'Israel had proved themselves worthy of the land', 'The land rested from war', 'God remembered his covenant with Abraham', 'Joshua was exalted above all Israel', 'a', 'Joshua 11:23 — "So Joshua took the whole land, according to all that the LORD said unto Moses; and Joshua gave it for an inheritance unto Israel according to their divisions by their tribes. And the land rested from war."'),
('Joshua', 11, 'adults', 8, 'Which Hivite city alone made peace with Israel and was not taken in battle in the broader Canaanite context referenced alongside chapter 11''s summary?', 'Jericho', 'Ai', 'Gibeon', 'Lachish', 'a', 'Joshua 11:19 — "There was not a city that made peace with the children of Israel, save the Hivites the inhabitants of Gibeon: all other they took in battle."');

-- ═══ Joshua Chapter 12 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Joshua', 12, 'kids', 1, 'Who was the giant king east of the Jordan with a very large iron bedstead?', 'Sihon', 'Og of Bashan', 'Jabin', 'Adoni-zedek', 'a', 'Joshua 12:4 — "And the coast of Og king of Bashan, which was of the remnant of the giants." Deuteronomy 3:11 records his iron bedstead.'),
('Joshua', 12, 'kids', 2, 'How many kings total did Joshua defeat west of the Jordan?', 'Ten', 'Twenty', 'Thirty-one', 'Forty', 'a', 'Joshua 12:24 — "All the kings thirty and one" were defeated by Joshua west of the Jordan.'),
('Joshua', 12, 'kids', 3, 'Who defeated the two kings east of the Jordan before Israel crossed?', 'Caleb', 'Moses', 'Aaron', 'Eleazar', 'a', 'Joshua 12:6 — "Them did Moses the servant of the LORD and the children of Israel smite."'),
-- Teens
('Joshua', 12, 'teens', 1, 'What were the names of the two kings east of the Jordan that Israel defeated under Moses?', 'Jabin and Jobab', 'Sihon and Og', 'Hoham and Piram', 'Japhia and Debir', 'a', 'Joshua 12:2, 4 — "Sihon king of the Amorites... And the coast of Og king of Bashan."'),
('Joshua', 12, 'teens', 2, 'From what river to what river did Sihon''s kingdom extend?', 'From the Nile to the Euphrates', 'From the Arnon to the Jabbok', 'From the Jordan to the Sea of Chinneroth', 'From Mount Hermon to the Negev', 'a', 'Joshua 12:2 — "Sihon king of the Amorites... which reigned in Heshbon, and ruled from Aroer, which is upon the bank of the river Arnon, and from the middle of the river, and from half Gilead, even unto the river Jabbok."'),
('Joshua', 12, 'teens', 3, 'What two kings'' territory together covered from Mount Hermon to the valley of Lebanon?', 'Sihon and Og', 'Jabin and Jobab', 'Adoni-zedek and Hoham', 'Piram and Japhia', 'a', 'Joshua 12:5 — "And reigned in mount Hermon, and in Salcah, and in all Bashan, unto the border of the Geshurites and the Maachathites, and half Gilead."'),
('Joshua', 12, 'teens', 4, 'Who gave the conquered eastern lands as an inheritance to the tribes of Reuben, Gad, and half-Manasseh?', 'Joshua', 'Eleazar the priest', 'Moses', 'The elders of Israel', 'a', 'Joshua 12:6 — "Them did Moses the servant of the LORD and the children of Israel smite: and Moses the servant of the LORD gave it for a possession unto the Reubenites, and the Gadites, and the half tribe of Manasseh."'),
('Joshua', 12, 'teens', 5, 'Including both sides of the Jordan, what was the total combined number of defeated kings listed in chapter 12?', 'Twenty-eight', 'Thirty-one', 'Thirty-three', 'Thirty-six', 'a', 'Joshua 12:7-24 lists thirty-one kings west of Jordan plus Sihon and Og (v.2-5) east of Jordan, totaling thirty-three kings in the chapter, with the western count specifically stated as "thirty and one."'),
-- Adults
('Joshua', 12, 'adults', 1, 'What geographical boundary on the east defined Sihon''s kingdom according to Joshua 12:3?', 'The sea of Chinneroth and unto the sea of the plain, even the salt sea', 'From the river of Egypt unto the great river Euphrates', 'From Kadesh-barnea to the brook of Egypt', 'From the wilderness of Paran to Hamath', 'a', 'Joshua 12:3 — "And from the plain to the sea of Chinneroth on the east, and unto the sea of the plain, even the salt sea on the east, the way to Beth-jeshimoth; and from the south, under Ashdoth-pisgah."'),
('Joshua', 12, 'adults', 2, 'What specific detail about Og indicates he was one of the last of the Rephaim?', 'His army was composed entirely of giants', 'He was of the remnant of the giants who reigned in Ashtaroth and Edrei', 'He stood twelve feet tall', 'He wielded an iron spear', 'a', 'Joshua 12:4 — "And the coast of Og king of Bashan, which was of the remnant of the giants, that dwelt at Ashtaroth and at Edrei."'),
('Joshua', 12, 'adults', 3, 'What phrase does chapter 12 use to introduce the list of kings defeated by Joshua west of the Jordan?', 'These are the kings of the land', 'And these are the kings of the country', 'Now these are they whom Joshua smote', 'The kings that Joshua destroyed are these', 'a', 'Joshua 12:7 — "And these are the kings of the country which Joshua and the children of Israel smote on this side Jordan on the west."'),
('Joshua', 12, 'adults', 4, 'What was the southern geographic limit of Joshua''s western conquest described in Joshua 12:8?', 'From Kadesh-barnea to the Mediterranean', 'In the mountains, and in the valleys, and in the plains, and in the springs, and in the wilderness, and in the south country', 'From the river of Egypt to the Arnon', 'From the Negev to Mount Hermon', 'a', 'Joshua 12:8 — "In the mountains, and in the valleys, and in the plains, and in the springs, and in the wilderness, and in the south country; the Hittites, the Amorites, and the Canaanites, the Perizzites, the Hivites, and the Jebusites."'),
('Joshua', 12, 'adults', 5, 'Which two back-to-back cities in the list of 31 kings share notable later biblical significance as Philistine strongholds?', 'Jericho and Ai', 'Gaza and Ekron', 'Gezer and Debir', 'Lachish and Eglon', 'a', 'Joshua 12:17 — "The king of Tappuah, one; the king of Hepher, one" — and later in the list are included Gezer and cities of the plain tied to Philistine territory in later biblical history.'),
('Joshua', 12, 'adults', 6, 'What literary form does the list in Joshua 12:9-24 follow, making it distinctive as a conquest record?', 'A poetic lament for the fallen kings', 'A formulaic "the king of X, one" inventory style', 'A narrative account of each battle', 'A priestly genealogy of conquered peoples', 'a', 'The list repeats "the king of [city], one" for each of the thirty-one kings, functioning as an official victory roster documenting the completeness of the conquest.'),
('Joshua', 12, 'adults', 7, 'The king of which city appears first in the western list, reflecting its primacy as the first city conquered?', 'Ai', 'Gibeon', 'Jericho', 'Hazor', 'a', 'Joshua 12:9 — "The king of Jericho, one; the king of Ai, which is beside Beth-el, one" — Jericho stands first as the gateway city of Canaan.'),
('Joshua', 12, 'adults', 8, 'What theological purpose does the comprehensive listing of defeated kings in chapter 12 serve in the book of Joshua''s narrative?', 'It proves Joshua was a greater military leader than Moses', 'It demonstrates the complete fulfillment of God''s promise to give Israel the land', 'It serves as a legal property record for future generations', 'It shows which nations still posed a threat to Israel', 'a', 'The exhaustive catalog of thirty-one kings conquered west of the Jordan, combined with the two eastern kings, demonstrates that God''s promise to Abraham and Moses was fully executed under Joshua''s leadership.');

-- ═══ Joshua Chapter 13 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Joshua', 13, 'kids', 1, 'What did God tell Joshua was still left to be done even though Joshua was old?', 'Build a temple', 'Divide the land among the tribes', 'Train a new army', 'Cross the Jordan again', 'a', 'Joshua 13:1 — "There remaineth yet very much land to be possessed."'),
('Joshua', 13, 'kids', 2, 'Which tribe received no land inheritance because the LORD was their inheritance?', 'Judah', 'Benjamin', 'Levi', 'Simeon', 'a', 'Joshua 13:33 — "But unto the tribe of Levi Moses gave not any inheritance: the LORD God of Israel was their inheritance."'),
('Joshua', 13, 'kids', 3, 'Which two tribes and part of a third tribe received land east of the Jordan River?', 'Judah and Ephraim', 'Reuben and Gad and half-Manasseh', 'Dan and Asher and Benjamin', 'Simeon and Issachar and Zebulun', 'a', 'Joshua 13:8 — "With whom the Reubenites and the Gadites have received their inheritance, which Moses gave them, beyond Jordan eastward."'),
-- Teens
('Joshua', 13, 'teens', 1, 'How old was Joshua when God told him there was still much land to possess?', 'Seventy years old', 'Eighty years old', 'Old and well stricken in years', 'A hundred years old', 'a', 'Joshua 13:1 — "Now Joshua was old and stricken in years; and the LORD said unto him, Thou art old and stricken in years, and there remaineth yet very much land to be possessed."'),
('Joshua', 13, 'teens', 2, 'Which Philistine territory is mentioned as land still unconquered at the opening of chapter 13?', 'The five lords of the Philistines', 'Gaza alone', 'The coast of Ashdod', 'The valley of Sorek', 'a', 'Joshua 13:3 — "From Sihor, which is before Egypt, even unto the borders of Ekron northward, which is counted to the Canaanite: five lords of the Philistines."'),
('Joshua', 13, 'teens', 3, 'What happened to Balaam son of Beor during the conquest of the eastern Amorites?', 'He escaped to Moab', 'He was taken captive', 'The children of Israel slew him with the sword', 'He converted and joined Israel', 'a', 'Joshua 13:22 — "Balaam also the son of Beor, the soothsayer, did the children of Israel slay with the sword among them that were slain by them."'),
('Joshua', 13, 'teens', 4, 'What was the river boundary on the south of the tribe of Reuben''s territory?', 'The river Jabbok', 'The river Arnon', 'The river Jordan', 'The river Euphrates', 'a', 'Joshua 13:16 — "And their coast was from Aroer, that is on the bank of the river Arnon, and the city that is in the midst of the river."'),
('Joshua', 13, 'teens', 5, 'What city was given to Reuben that was formerly a royal seat of Sihon king of the Amorites?', 'Ar of Moab', 'Heshbon', 'Dibon', 'Medeba', 'a', 'Joshua 13:17 — "Heshbon, and all her cities that are in the plain; Dibon, and Bamoth-baal, and Beth-baal-meon" — Heshbon was Sihon''s capital (Numbers 21:26).'),
-- Adults
('Joshua', 13, 'adults', 1, 'What specific Geshurite and Maachathite territory in the north is noted as unconquered even after the campaigns of Joshua?', 'The land of Sidon and the coast of Byblos', 'Geshur and Maachath dwell among Israel unto this day', 'The cities of the Anakim in the hill country', 'The plain of Jezreel and Megiddo', 'a', 'Joshua 13:13 — "Nevertheless the children of Israel expelled not the Geshurites, nor the Maachathites: but the Geshurites and the Maachathites dwell among the children of Israel until this day."'),
('Joshua', 13, 'adults', 2, 'What was the full extent of the half-tribe of Manasseh''s eastern territory according to chapter 13?', 'From the Jabbok to Mount Hermon including all Bashan', 'From Medeba to the sea of Chinneroth', 'From the Arnon to the Jabbok only', 'From Gilgal to the plains of Moab', 'a', 'Joshua 13:31 — "And half Gilead, and Ashtaroth, and Edrei, cities of the kingdom of Og in Bashan, were pertaining unto the children of Machir the son of Manasseh."'),
('Joshua', 13, 'adults', 3, 'Why does chapter 13 give Moses the credit for distributing the eastern territories rather than Joshua?', 'Moses was a greater leader than Joshua', 'Moses had distributed these lands before his death as commanded by God', 'Joshua refused to divide the eastern lands', 'The eastern tribes chose their own lands', 'a', 'Joshua 13:8 — "With whom the Reubenites and the Gadites have received their inheritance, which Moses gave them, beyond Jordan eastward, even as Moses the servant of the LORD gave them."'),
('Joshua', 13, 'adults', 4, 'What five princes of Midian are listed as vassal rulers slain by Israel alongside Sihon?', 'Evi, Rekem, Zur, Hur, and Reba', 'Balak, Balaam, Zimri, Cozbi, and Phinehas', 'Og, Sihon, Jabin, Jobab, and Japh', 'Hoham, Piram, Japhia, Debir, and Adoni', 'a', 'Joshua 13:21 — "And all the kingdom of Sihon king of the Amorites... Evi, and Rekem, and Zur, and Hur, and Reba, which were dukes of Sihon, dwelling in the country."'),
('Joshua', 13, 'adults', 5, 'What specific phrase describes why the Levites received no territorial inheritance, distinguishing them from all other tribes?', 'The Levites were too holy to own land', 'The LORD God of Israel was their inheritance', 'They were given the tithes of all Israel instead', 'The priesthood was their portion among their brethren', 'a', 'Joshua 13:33 — "But unto the tribe of Levi Moses gave not any inheritance: the LORD God of Israel was their inheritance, as he said unto them."'),
('Joshua', 13, 'adults', 6, 'Which portion of Gad''s territory included the lower half of Gilead and the Jordan plain?', 'From Mahanaim to the border of Debir', 'From Aroer by the Arnon to the border of the children of Ammon', 'Jazer, and all the cities of Gilead, and half the land of the children of Ammon', 'From Ramoth in Gilead to the sea of Chinneroth', 'a', 'Joshua 13:25 — "And their coast was Jazer, and all the cities of Gilead, and half the land of the children of Ammon, unto Aroer that is before Rabbah."'),
('Joshua', 13, 'adults', 7, 'What does the description of Reuben''s territory as extending "unto the sea of Chinneroth on the east" suggest about ancient boundaries?', 'Reuben controlled all of the Sea of Galilee''s eastern shore', 'Geographic borders followed natural water features rather than political agreements', 'The Sea of Chinneroth was Reuben''s primary water source', 'The tribe used the sea for fishing as their livelihood', 'a', 'Joshua 13:27 — "And in the valley, Beth-aram, and Beth-nimrah, and Succoth, and Zaphon, the rest of the kingdom of Sihon king of Heshbon, Jordan and his border, even unto the edge of the sea of Chinneroth on the other side Jordan eastward."'),
('Joshua', 13, 'adults', 8, 'What title is given to Balaam in Joshua 13:22 that is not found in the Numbers narrative, adding to his characterization?', 'Balaam the prophet', 'Balaam the soothsayer', 'Balaam the seer of visions', 'Balaam the Midianite priest', 'a', 'Joshua 13:22 — "Balaam also the son of Beor, the soothsayer, did the children of Israel slay with the sword among them that were slain by them."');

-- ═══ Joshua Chapter 14 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Joshua', 14, 'kids', 1, 'What famous old man boldly asked Joshua for a mountain as his inheritance?', 'Moses', 'Caleb', 'Aaron', 'Eleazar', 'a', 'Joshua 14:12 — "Now therefore give me this mountain, whereof the LORD spake in that day."'),
('Joshua', 14, 'kids', 2, 'How old was Caleb when he asked for his inheritance?', 'Seventy years old', 'Eighty-five years old', 'A hundred years old', 'Sixty years old', 'a', 'Joshua 14:10 — "And now, behold, the LORD hath kept me alive, as he said, these forty and five years... I am this day fourscore and five years old."'),
('Joshua', 14, 'kids', 3, 'Which city did Caleb receive as his inheritance?', 'Jericho', 'Shiloh', 'Hebron', 'Beersheba', 'a', 'Joshua 14:13 — "And Joshua blessed him, and gave unto Caleb the son of Jephunneh Hebron for an inheritance."'),
-- Teens
('Joshua', 14, 'teens', 1, 'Who helped Joshua divide the land by lot as commanded through Moses?', 'The seventy elders of Israel', 'Eleazar the priest and the heads of the fathers'' tribes', 'The captains of thousands and hundreds', 'The Levites and the priests together', 'a', 'Joshua 14:1 — "And these are the countries which the children of Israel inherited in the land of Canaan, which Eleazar the priest, and Joshua the son of Nun, and the heads of the fathers of the tribes of the children of Israel, distributed for inheritance to them."'),
('Joshua', 14, 'teens', 2, 'What had Caleb done differently from the other spies that earned him a special promise from God?', 'He went alone to spy the land', 'He wholly followed the LORD his God', 'He fought against the giants single-handedly', 'He prayed every day for forty years', 'a', 'Joshua 14:9 — "Surely the land whereon thy feet have trodden shall be thine inheritance... because thou hast wholly followed the LORD my God."'),
('Joshua', 14, 'teens', 3, 'How old was Caleb when Moses sent him to spy out the land from Kadesh-barnea?', 'Thirty years old', 'Forty years old', 'Fifty years old', 'Twenty-five years old', 'a', 'Joshua 14:7 — "Forty years old was I when Moses the servant of the LORD sent me from Kadesh-barnea to espy out the land."'),
('Joshua', 14, 'teens', 4, 'What reason did Caleb give to show he was still strong enough to take on the giants at age 85?', 'God had promised him victory directly', 'He was as strong as the day Moses sent him out', 'He had trained warriors from his own tribe', 'He had fought the Philistines successfully already', 'a', 'Joshua 14:11 — "As yet I am as strong this day as I was in the day that Moses sent me: as my strength was then, even so is my strength now, for war, both to go out, and to come in."'),
('Joshua', 14, 'teens', 5, 'Why did Joseph''s descendants count as two tribes for the purposes of land distribution, totaling twelve land-receiving tribes?', 'Because Joseph was double honored for saving Egypt', 'Because Ephraim and Manasseh each received a separate portion while Levi received none', 'Because Moses decreed it before his death', 'Because Joseph''s two sons were born in Egypt and needed extra land', 'a', 'Joshua 14:4 — "For the children of Joseph were two tribes, Manasseh and Ephraim: therefore they gave no part unto the Levites in the land, save cities to dwell in."'),
-- Adults
('Joshua', 14, 'adults', 1, 'What method was used to assign the nine and a half western tribes their land, and where did this take place?', 'Drawing of straws at Gilgal', 'Casting of lots at Shiloh before the LORD', 'Lot casting at Gilgal', 'Division by Joshua''s decree at Shechem', 'a', 'Joshua 14:2 — "By lot was their inheritance, as the LORD commanded by the hand of Moses, for the nine tribes, and for the half tribe."'),
('Joshua', 14, 'adults', 2, 'What was the content of the word that Moses swore to Caleb on the day he returned from spying, quoted by Caleb in his appeal?', 'Caleb would rule over all of Judah', 'Surely the land whereon thy feet have trodden shall be thine inheritance', 'Thou shalt smite all the Anakim', 'I will give thee the mountain and the valley both', 'a', 'Joshua 14:9 — "And Moses sware on that day, saying, Surely the land whereon thy feet have trodden shall be thine inheritance, and thy children''s for ever, because thou hast wholly followed the LORD my God."'),
('Joshua', 14, 'adults', 3, 'What does Caleb''s statement "the LORD hath kept me alive these forty and five years" reveal about the timeline of the conquest?', 'The conquest lasted exactly 45 years', 'From Kadesh-barnea to the distribution was 45 years (38 wilderness + ~7 conquest)', 'Caleb wandered alone for 45 years before the crossing', 'Moses''s promise was made 45 years before the Exodus', 'a', 'Joshua 14:10 — "And now, behold, the LORD hath kept me alive, as he said, these forty and five years, even since the LORD spake this word unto Moses, while the children of Israel wandered in the wilderness."'),
('Joshua', 14, 'adults', 4, 'What does the phrase "wholly followed the LORD" (used three times regarding Caleb in chapter 14) indicate theologically?', 'Caleb never sinned', 'Undivided allegiance and full obedience distinguishing him from fearful Israel', 'Caleb observed all ceremonial laws perfectly', 'Caleb refused to fight except when God commanded', 'a', 'Joshua 14:8 — "But I wholly followed the LORD my God" — the repetition of this phrase underscores the contrast with the ten fearful spies and the faithless generation.'),
('Joshua', 14, 'adults', 5, 'By what other name was Hebron known before Caleb took it, and what does that name mean in context?', 'Laish, meaning "lion"', 'Kirjath-arba, named after Arba the greatest man among the Anakim', 'Kiriath-jearim, meaning "city of forests"', 'Beth-el, meaning "house of God"', 'a', 'Joshua 14:15 — "And the name of Hebron before was Kirjath-arba; which Arba was a great man among the Anakims."'),
('Joshua', 14, 'adults', 6, 'What does Joshua''s response to Caleb''s request — "Joshua blessed him" before granting Hebron — suggest about their relationship?', 'Joshua was spiritually superior to Caleb', 'Joshua affirmed Caleb''s faith and honored the divine promise', 'The blessing was a required legal formality for land grants', 'Joshua was uncertain Caleb could succeed against the Anakim', 'a', 'Joshua 14:13 — "And Joshua blessed him, and gave unto Caleb the son of Jephunneh Hebron for an inheritance." The blessing acknowledges Caleb''s lifelong faithfulness.'),
('Joshua', 14, 'adults', 7, 'From which non-Israelite tribe was Caleb descended, making his faithfulness even more remarkable?', 'The Moabites', 'The Kenizzites', 'The Kenites', 'The Midianites', 'a', 'Joshua 14:6 — "Then the children of Judah came unto Joshua in Gilgal: and Caleb the son of Jephunneh the Kenezite said unto him."'),
('Joshua', 14, 'adults', 8, 'What final statement closes chapter 14, connecting back to the theme of spiritual rest in the land?', 'Israel gave thanks to God for the inheritance', 'The land had rest from war', 'All the tribes received their portions and rejoiced', 'Eleazar recorded all the inheritances in a book', 'a', 'Joshua 14:15 — "And the name of Hebron before was Kirjath-arba... And the land had rest from war."');

-- ═══ Joshua Chapter 15 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Joshua', 15, 'kids', 1, 'Who did Caleb''s daughter Achsah ask for water from?', 'Joshua', 'Her husband Othniel', 'Her father Caleb', 'Eleazar the priest', 'a', 'Joshua 15:18-19 — "She moved him to ask of her father a field: and she lighted off her ass; and Caleb said unto her, What wouldest thou? Who answered, Give me a blessing; for thou hast given me a south land; give me also springs of water."'),
('Joshua', 15, 'kids', 2, 'Who captured the city of Kirjath-sepher and married Caleb''s daughter as a reward?', 'Joshua', 'Othniel the son of Kenaz', 'Phinehas', 'Salmon', 'a', 'Joshua 15:17 — "And Othniel the son of Kenaz, the brother of Caleb, took it: and he gave him Achsah his daughter to wife."'),
('Joshua', 15, 'kids', 3, 'Which tribe received the land in the south of Canaan that included the city of Hebron?', 'Simeon', 'Dan', 'Judah', 'Ephraim', 'a', 'Joshua 15:1 — "This then was the lot of the tribe of the children of Judah by their families."'),
-- Teens
('Joshua', 15, 'teens', 1, 'What spring at the south border of Judah''s territory marked the beginning of the Judah-Edom boundary?', 'En-gedi', 'The spring of the waters of Nephtoah', 'The ascent of Akrabbim at the south side of the Salt Sea', 'The well of Beersheba', 'a', 'Joshua 15:2-3 — "And their south border was from the shore of the salt sea, from the bay that looketh southward: And it went out to the south side to Maaleh-acrabbim."'),
('Joshua', 15, 'teens', 2, 'What former name did the city Hebron bear before Caleb drove out the Anakim?', 'Kiriath-jearim', 'Kirjath-arba', 'Kirjath-sepher', 'Debir', 'a', 'Joshua 15:13 — "And unto Caleb the son of Jephunneh he gave a part among the children of Judah, according to the commandment of the LORD to Joshua, even the city of Arba the father of Anak, which city is Hebron."'),
('Joshua', 15, 'teens', 3, 'What did Achsah receive from her father Caleb after her request?', 'Gold and silver', 'The upper and lower springs', 'A portion of Hebron', 'The city of Debir', 'a', 'Joshua 15:19 — "And he gave her the upper springs, and the nether springs."'),
('Joshua', 15, 'teens', 4, 'How many cities of Judah are listed in the Negev district of Joshua 15?', 'Thirteen cities', 'Fourteen cities', 'Twenty-nine cities', 'Thirty-six cities', 'a', 'Joshua 15:32 — "All the cities are twenty and nine, with their villages" — the Negev district of Judah counted twenty-nine cities.'),
('Joshua', 15, 'teens', 5, 'Which people could Judah not drive out and continued to dwell with them in Jerusalem?', 'The Philistines', 'The Jebusites', 'The Hivites', 'The Perizzites', 'a', 'Joshua 15:63 — "As for the Jebusites the inhabitants of Jerusalem, the children of Judah could not drive them out: but the Jebusites dwell with the children of Judah at Jerusalem unto this day."'),
-- Adults
('Joshua', 15, 'adults', 1, 'What landmark in the wilderness of Zin defined the extreme southern border of Judah''s territory?', 'The brook of Egypt to the great sea', 'The salt sea at the end of Jordan and the border of Edom', 'The ascent of Akrabbim and passing along to Zin', 'The plain of Mamre and the city of Beersheba', 'a', 'Joshua 15:1-2 — "This then was the lot of the tribe of the children of Judah by their families; even to the border of Edom the wilderness of Zin southward was the uttermost part of the south coast."'),
('Joshua', 15, 'adults', 2, 'What is the western boundary of Judah stated to be in Joshua 15:12?', 'The river of Egypt', 'The great sea, and the coast thereof', 'The Jordan River', 'The Mediterranean coast from Gaza to Joppa', 'a', 'Joshua 15:12 — "And the west border was to the great sea, and the coast thereof. This is the coast of the children of Judah round about according to their families."'),
('Joshua', 15, 'adults', 3, 'What was the original name of Debir before Othniel captured it?', 'Kirjath-arba', 'Kirjath-sepher', 'Kirjath-jearim', 'Eglon', 'a', 'Joshua 15:15 — "And he went up thence to the inhabitants of Debir: and the name of Debir before was Kirjath-sepher."'),
('Joshua', 15, 'adults', 4, 'What is the theological significance of Othniel the son of Kenaz capturing Kirjath-sepher (meaning "city of the book")?', 'It showed military prowess earned his wife', 'Othniel later became Israel''s first judge, so his early courage foreshadows his leadership', 'The capture fulfilled a specific prophecy about Judah', 'It demonstrated that Caleb''s family line was more powerful than the giants', 'a', 'Othniel son of Kenaz appears again in Judges 3:9-10 as Israel''s first judge and deliverer, making this moment in Joshua 15:17 the introduction of a major figure in the Judges narrative.'),
('Joshua', 15, 'adults', 5, 'How are the cities of Judah organized in the detailed listing of chapter 15?', 'Alphabetically by city name', 'By districts — Negev, Shephelah, hill country, and wilderness', 'By size from smallest to largest', 'By the order Judah captured them', 'a', 'Joshua 15:20-63 organizes Judah''s cities into geographic districts: the Negev (v.21-32), the Shephelah/foothills (v.33-47), the hill country (v.48-60), and the wilderness (v.61-62).'),
('Joshua', 15, 'adults', 6, 'What phrase does Joshua 15:63 use that recurs throughout the land distribution narratives to indicate incomplete conquest?', 'The tribe could not drive them out', 'They dwell unto this day', 'The people remained in the land', 'Israel lived among them', 'a', 'Joshua 15:63 — "The Jebusites dwell with the children of Judah at Jerusalem unto this day" — this phrase marks ongoing Canaanite presence despite incomplete obedience.'),
('Joshua', 15, 'adults', 7, 'What does Achsah''s bold request for springs of water, called "a blessing," reveal about property rights in ancient Israel?', 'Women had no property rights unless they married', 'Daughters could appeal to fathers for additional land resources as a familial blessing', 'Water rights were always separate from land grants', 'Only priests could grant springs as they belonged to God', 'a', 'Joshua 15:19 — "Give me a blessing; for thou hast given me a south land; give me also springs of water" — Achsah''s assertion parallels the daughters of Zelophehad who also appealed for inheritance rights.'),
('Joshua', 15, 'adults', 8, 'What is the total number of cities listed for Judah across all its districts in chapter 15, excluding villages?', 'Forty cities', 'Approximately 112 cities', 'Seventy cities', 'Eighty-five cities', 'a', 'The various district totals in Joshua 15:32, 36, 41, 44, 47, 54, 57, 59, 60, 62 together enumerate a large number of cities, with scholars calculating approximately 112 named cities total across Judah''s allotment.');

-- ═══ Joshua Chapter 16 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Joshua', 16, 'kids', 1, 'Which two sons of Joseph received land in Canaan?', 'Reuben and Gad', 'Ephraim and Manasseh', 'Benjamin and Dan', 'Simeon and Levi', 'a', 'Joshua 16:1 — "And the lot of the children of Joseph fell from Jordan by Jericho... The children of Joseph, Ephraim and Manasseh."'),
('Joshua', 16, 'kids', 2, 'Which people lived in the city of Gezer and were not driven out by Ephraim?', 'The Jebusites', 'The Anakim', 'The Canaanites', 'The Philistines', 'a', 'Joshua 16:10 — "And they drave not out the Canaanites that dwelt in Gezer: but the Canaanites dwell among the Ephraimites unto this day."'),
('Joshua', 16, 'kids', 3, 'What was the western border of the Joseph tribes'' territory?', 'The Jordan River', 'The great sea', 'The Dead Sea', 'The Arnon River', 'a', 'Joshua 16:3 — "And goeth down westward to the coast of Japhleti, unto the coast of Beth-horon the nether, and to Gezer: and the goings out thereof are at the sea."'),
-- Teens
('Joshua', 16, 'teens', 1, 'What geographical feature formed the southern border of the Joseph tribes'' combined territory?', 'The Jordan from Jericho to Beth-el', 'The brook Kanah', 'The mountains of Ephraim', 'The valley of Jezreel', 'a', 'Joshua 16:1-2 — "And the lot of the children of Joseph fell from Jordan by Jericho, unto the water of Jericho on the east, to the wilderness that goeth up from Jericho throughout mount Bethel."'),
('Joshua', 16, 'teens', 2, 'What special arrangement was made regarding the Canaanites still living in Gezer after Ephraim''s failure to expel them?', 'They were destroyed later by Solomon', 'They became servants under tribute', 'They were absorbed into Ephraim''s clans', 'They were expelled by Manasseh instead', 'a', 'Joshua 16:10 — "And they drave not out the Canaanites that dwelt in Gezer: but the Canaanites dwell among the Ephraimites unto this day, and serve under tribute."'),
('Joshua', 16, 'teens', 3, 'What was the northern border city of Ephraim''s territory according to chapter 16?', 'Shiloh', 'Michmethah', 'Janoah', 'Taanath-shiloh', 'a', 'Joshua 16:6 — "And the border went out toward the sea to Michmethah on the north side; and the border went about eastward unto Taanath-shiloh."'),
('Joshua', 16, 'teens', 4, 'What cities within Manasseh''s territory are noted as belonging to Ephraim, creating an unusual enclave arrangement?', 'Shiloh and Gibeon', 'Beth-el and Ai', 'Gezer and Timnath', 'Separate cities for Ephraim among Manasseh''s inheritance', 'a', 'Joshua 16:9 — "And the separate cities for the children of Ephraim were among the inheritance of the children of Manasseh, all the cities with their villages."'),
('Joshua', 16, 'teens', 5, 'From what major city did the southern border of Joseph''s lot begin?', 'Jericho', 'Gaza', 'Beer-sheba', 'Hebron', 'a', 'Joshua 16:1 — "And the lot of the children of Joseph fell from Jordan by Jericho, unto the water of Jericho on the east, to the wilderness."'),
-- Adults
('Joshua', 16, 'adults', 1, 'What does the fact that the Joseph tribes received a single combined lot before being individually subdivided suggest about the allocation process?', 'They were treated as one tribe for population purposes', 'The collective lot was first cast for Joseph''s house, then subdivided between Ephraim and Manasseh', 'Joshua favored the house of Joseph above all others', 'They asked to be assigned land together for defense', 'a', 'Joshua 16:1 — "And the lot of the children of Joseph fell from Jordan by Jericho" — the lot for Joseph''s house was drawn as a unit because he was a patriarchal ancestor, with the subdivision following in chapters 16-17.'),
('Joshua', 16, 'adults', 2, 'What does the phrase "goings out thereof are at the sea" indicate about how ancient Israel described borders?', 'The border ended at the Mediterranean coast', 'Terminal points of borders were designated by natural features', 'The tribe had naval rights to the sea', 'The coast was shared among all tribes equally', 'a', 'Joshua 16:3 — "And goeth down westward to the coast of Japhleti, unto the coast of Beth-horon the nether, and to Gezer: and the goings out thereof are at the sea."'),
('Joshua', 16, 'adults', 3, 'What is the theological problem with Ephraim''s failure to expel the Canaanites from Gezer, in light of God''s commands in Deuteronomy?', 'It violated the rule of holy war which required total destruction', 'It was permissible since the Canaanites paid tribute', 'It only affected commerce, not worship', 'It was justified because Gezer was outside Canaan''s borders', 'a', 'Deuteronomy 20:17 commanded total destruction of the seven Canaanite nations. Ephraim''s compromise in Joshua 16:10 — keeping Canaanites as tribute payers — violated this command and planted seeds for later apostasy.'),
('Joshua', 16, 'adults', 4, 'Which city at the descent of Beth-horon appears in Ephraim''s border description and later gained significance as a site of military battles?', 'Gezer', 'Beth-horon', 'Taanath-shiloh', 'Ataroth', 'a', 'Joshua 16:3 — Beth-horon is specifically mentioned at the descent, and it later appears in 1 Samuel 13 and 1 Maccabees 3 as a strategic military pass.'),
('Joshua', 16, 'adults', 5, 'What does the description of Ephraim''s territory note about the relationship between outer limits and inner enclaves?', 'Ephraim''s outer border was small but it had cities scattered within Manasseh', 'Ephraim had no enclaves and a compact unified territory', 'Manasseh held enclaves within Ephraim''s boundary', 'The two tribes had perfectly symmetrical territories', 'a', 'Joshua 16:9 — "And the separate cities for the children of Ephraim were among the inheritance of the children of Manasseh, all the cities with their villages."'),
('Joshua', 16, 'adults', 6, 'What river is mentioned as part of Ephraim''s northern border with Manasseh?', 'The Jordan River', 'The brook Kanah', 'The Jabbok River', 'The Kishon River', 'a', 'Joshua 17:9 — "And the coast descended unto the river Kanah, southward of the river: these cities of Ephraim are among the cities of Manasseh." The Kanah serves as the border.'),
('Joshua', 16, 'adults', 7, 'How does Joshua 16 fit within the broader structure of the land distribution chapters (13-21) and what transition does it mark?', 'It closes the eastern distribution and begins the western', 'It begins the western tribal allotments with the premier tribe of Joseph', 'It ends the summary of unconquered lands and starts detailed allotments', 'It marks the halfway point in allotments with a summary of all previous grants', 'a', 'Chapter 16 begins the detailed allotments for the western tribes with the house of Joseph (chapters 16-17), following the eastern allotments (ch. 13) and Caleb''s special claim (ch. 14-15).'),
('Joshua', 16, 'adults', 8, 'What does the tribute arrangement with the Canaanites of Gezer foreshadow in later Israelite history?', 'Israel''s eventual ability to absorb all Canaanites peacefully', 'The dangerous pattern of coexistence that Solomon later institutionalized with forced labor', 'The legal framework for converting Gentiles into Israelites', 'A pragmatic solution God ultimately approved', 'a', 'The tribute-labor arrangement in Joshua 16:10 is a precursor to the forced labor corps Solomon established with Canaanites in 1 Kings 9:20-21, showing a consistent pattern of incomplete obedience in dealing with the original inhabitants.');

-- ═══ Joshua Chapter 17 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Joshua', 17, 'kids', 1, 'What did the daughters of Zelophehad successfully ask for because their father had no sons?', 'Permission to marry outside the tribe', 'An inheritance among their father''s brethren', 'Land east of the Jordan', 'A city of their own', 'a', 'Joshua 17:4 — "And they came near before Eleazar the priest, and before Joshua the son of Nun, and before the princes, saying, The LORD commanded Moses to give us an inheritance among our brethren."'),
('Joshua', 17, 'kids', 2, 'What did the tribe of Joseph complain to Joshua that they needed more of?', 'Food and water', 'Soldiers and weapons', 'Land, because they were too many people', 'Cities and roads', 'a', 'Joshua 17:14 — "And the children of Joseph spake unto Joshua, saying, Why hast thou given me but one lot and one portion to inherit, seeing I am a great people?"'),
('Joshua', 17, 'kids', 3, 'What did Joshua tell the house of Joseph to do if the hill country was not enough for them?', 'Wait for more land to be conquered', 'Go up and cut down the forest and make room for themselves', 'Ask Eleazar for a second lot', 'Move to the eastern side of Jordan', 'a', 'Joshua 17:15 — "Get thee up to the wood country, and cut down for thyself there in the land of the Perizzites and of the giants."'),
-- Teens
('Joshua', 17, 'teens', 1, 'What was the name of the first-born of Manasseh, who was the father of Gilead and received the eastern territory?', 'Asriel', 'Machir', 'Helek', 'Shechem', 'a', 'Joshua 17:1 — "There was also a lot for the tribe of Manasseh; for he was the firstborn of Joseph; to wit, for Machir the firstborn of Manasseh, the father of Gilead: because he was a man of war, therefore he had Gilead and Bashan."'),
('Joshua', 17, 'teens', 2, 'How many named sons of Manasseh''s son Gilead received their portions in chapter 17?', 'Five sons', 'Six sons', 'Seven sons', 'Ten sons', 'a', 'Joshua 17:2 — Lists Abiezer, Helek, Asriel, Shechem, Hepher, and Shemida — six male clans of Manasseh received their portions.'),
('Joshua', 17, 'teens', 3, 'What earlier ruling by Moses regarding Zelophehad''s daughters did Joshua confirm when they came before him?', 'That women could own property only until they married', 'That Moses had commanded to give them inheritance among their brethren', 'That they must marry within their tribe to keep the land', 'That their inheritance would revert to the tribe after one generation', 'a', 'Joshua 17:4 — "The LORD commanded Moses to give us an inheritance among our brethren. Therefore according to the commandment of the LORD he gave them an inheritance among the brethren of their father."'),
('Joshua', 17, 'teens', 4, 'What specific obstacle did the tribe of Manasseh face in the valley that prevented them from driving out certain Canaanites?', 'The Canaanites had walled cities', 'They had chariots of iron', 'The giants were too large to fight', 'Manasseh lacked enough warriors', 'a', 'Joshua 17:16 — "The hill is not enough for us: and all the Canaanites that dwell in the land of the valley have chariots of iron, both they who are of Beth-shean and his towns, and they who are of the valley of Jezreel."'),
('Joshua', 17, 'teens', 5, 'What was Joshua''s confident reply to the complaint that the Canaanites had iron chariots?', 'Wait for God to send an angel to fight them', 'Thou art a great people, and hast great power: thou shalt drive them out', 'Ask for more soldiers from the other tribes', 'Build a stronger army before attacking', 'a', 'Joshua 17:18 — "But the mountain shall be thine; for it is a wood, and thou shalt cut it down: and the outgoings of it shall be thine: for thou shalt drive out the Canaanites, though they have iron chariots, and though they be strong."'),
-- Adults
('Joshua', 17, 'adults', 1, 'What does it mean that Machir received Gilead and Bashan because "he was a man of war," and how does this connect to Numbers 32?', 'Military merit determined land grants for exceptional warriors', 'Machir''s military prowess in helping conquer Bashan secured his eastern territory as promised by Moses', 'Machir was rewarded for spying out the land', 'The eastern territory was given only to fighting men, not families', 'a', 'Joshua 17:1 — "because he was a man of war, therefore he had Gilead and Bashan" — this reflects Numbers 32:39-40 where Machir''s descendants took Gilead and Moses gave it to them.'),
('Joshua', 17, 'adults', 2, 'What legal precedent established in Numbers 27 is confirmed in Joshua 17:3-4 regarding the daughters of Zelophehad?', 'Women inherit equally with men in all cases', 'When a man dies with no sons, his daughters receive his inheritance', 'Female heirs must marry within their clan to keep land in the tribe', 'Property inheritance follows the male line exclusively in Israel', 'a', 'Numbers 27:7-8 established the ruling: "The daughters of Zelophehad speak right... thou shalt cause the inheritance of their father to pass unto them." Joshua 17:4 confirms this ruling was executed.'),
('Joshua', 17, 'adults', 3, 'What was the total number of portions that Manasseh received in the western allotment, as specifically stated in chapter 17?', 'Five portions', 'Ten portions', 'Seven portions', 'Twelve portions', 'a', 'Joshua 17:5 — "And there fell ten pieces to Manasseh, beside the land of Gilead and Bashan, which were on the other side Jordan."'),
('Joshua', 17, 'adults', 4, 'What boundary did the tribe of Manasseh share with Asher to the north and Issachar to the east, as described in chapter 17?', 'The brook Kanah and the Mediterranean coast', 'The valley of Jezreel and mount Carmel', 'The river Jordan from Megiddo to the sea of Chinneroth', 'The mountains of Ephraim along the entire length', 'a', 'Joshua 17:10-11 — "Southward it was Ephraim''s, and northward it was Manasseh''s, and the sea is his border; and they met together in Asher on the north, and in Issachar on the east."'),
('Joshua', 17, 'adults', 5, 'Why is it significant that Manasseh could not drive out the cities in the valley even though they "could" eventually do so according to Joshua?', 'It reveals that iron chariots were genuinely invincible in ancient warfare', 'It shows the difference between capability and will — Manasseh had the power but lacked the faith to exercise it', 'It demonstrates God temporarily withheld his power from Manasseh', 'It proves the conquest was incomplete because Israel lacked sufficient population', 'a', 'Joshua 17:12-13 — "Yet the children of Manasseh could not drive out the inhabitants of those cities... But it came to pass, when the children of Israel were waxen strong, that they put the Canaanites to tribute; but did not utterly drive them out." They could but chose tribute over obedience.'),
('Joshua', 17, 'adults', 6, 'What does Joseph''s complaint about receiving "but one lot" reveal about the expected relationship between tribal population size and land allocation?', 'Each tribe expected exactly equal geographic area', 'Larger tribes anticipated proportionally larger territorial grants', 'Population was irrelevant to the lot-casting process', 'Joseph expected special treatment as Jacob''s favorite son', 'a', 'Joshua 17:14 — "Why hast thou given me but one lot and one portion to inherit, seeing I am a great people, forasmuch as the LORD hath blessed me hitherto?" The complaint assumes population entitles a tribe to more land.'),
('Joshua', 17, 'adults', 7, 'What does Joshua''s challenge to cut down the forest demonstrate about his theology of divine promise and human effort?', 'God only helps those who do nothing themselves', 'Divine promises require human initiative and effort to be realized', 'God had already cleared the land before Israel arrived', 'Forest clearing was a spiritual act of worship', 'a', 'Joshua 17:15 — "If thou be a great people, then get thee up to the wood country, and cut down for thyself" — Joshua insists that God''s promise of land does not eliminate the need for the tribe''s own effort and courage.'),
('Joshua', 17, 'adults', 8, 'How does the narrative of Zelophehad''s daughters in Joshua 17 function within the broader theme of the book of Joshua?', 'It interrupts the conquest narrative with a domestic legal dispute', 'It demonstrates God''s justice extending even to women and protecting their inheritance rights within the covenant community', 'It primarily records a legal exception that applied only to the Manasseh tribe', 'It shows that women''s concerns were secondary in the land distribution process', 'a', 'The daughters of Zelophehad (Joshua 17:3-6) successfully appealed for their rightful inheritance, demonstrating that God''s covenant promises of land extended to all covenant members regardless of gender, fulfilling Numbers 27 and showing the integrity of Moses''s legal rulings.');

-- ═══ Joshua Chapter 18 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Joshua', 18, 'kids', 1, 'Where did the whole congregation of Israel set up the tabernacle in chapter 18?', 'Jericho', 'Gilgal', 'Shiloh', 'Shechem', 'a', 'Joshua 18:1 — "And the whole congregation of the children of Israel assembled together at Shiloh, and set up the tabernacle of the congregation there."'),
('Joshua', 18, 'kids', 2, 'How many tribes still had not received their land when chapter 18 begins?', 'Three tribes', 'Five tribes', 'Seven tribes', 'Nine tribes', 'a', 'Joshua 18:2 — "And there remained among the children of Israel seven tribes, which had not yet received their inheritance."'),
('Joshua', 18, 'kids', 3, 'What tribe received its land by lot in chapter 18?', 'Ephraim', 'Manasseh', 'Benjamin', 'Simeon', 'a', 'Joshua 18:11 — "And the lot of the tribe of the children of Benjamin came up according to their families: and the coast of their lot came forth between the children of Judah and the children of Joseph."'),
-- Teens
('Joshua', 18, 'teens', 1, 'What did Joshua command to be done before casting lots for the remaining seven tribes?', 'Build an altar and offer sacrifices', 'Send three men from each tribe to survey and describe the land', 'Fast and pray for seven days', 'Ask Eleazar to consult the Urim', 'a', 'Joshua 18:4 — "Give out from among you three men for each tribe: and I will send them, and they shall rise, and go through the land, and describe it according to the inheritance of them; and they shall come again to me."'),
('Joshua', 18, 'teens', 2, 'Into how many parts was the land divided in the survey before the lots were cast?', 'Five parts', 'Seven parts', 'Ten parts', 'Twelve parts', 'a', 'Joshua 18:5-6 — "And they shall divide it into seven parts... and I will cast lots for you here before the LORD our God."'),
('Joshua', 18, 'teens', 3, 'What rebuke did Joshua give to the seven tribes who had not yet gone to take possession of their land?', 'God will punish your laziness with defeat', 'How long are ye slack to go to possess the land?', 'Your fathers would be ashamed of your cowardice', 'You have failed to trust the word of the LORD', 'a', 'Joshua 18:3 — "And Joshua said unto the children of Israel, How long are ye slack to go to possess the land, which the LORD God of your fathers hath given you?"'),
('Joshua', 18, 'teens', 4, 'What city was the northern boundary of Benjamin''s territory, marking the border with Ephraim?', 'Jericho', 'Beth-el', 'Gibeon', 'Ramah', 'a', 'Joshua 18:13 — "And the border went over from thence toward Luz, to the side of Luz, which is Beth-el, southward."'),
('Joshua', 18, 'teens', 5, 'Where exactly did Joshua cast the lots for the seven remaining tribes?', 'Before the ark of the covenant in Gilgal', 'Before the LORD in Shiloh', 'At the door of the tabernacle of the congregation', 'In the gates of the city of Shiloh', 'a', 'Joshua 18:8 — "And the men arose, and went away: and Joshua charged them that went to describe the land, saying, Go and walk through the land, and describe it, and come again to me, that I may here cast lots for you before the LORD in Shiloh."'),
-- Adults
('Joshua', 18, 'adults', 1, 'What is the theological significance of moving the tabernacle to Shiloh at this point in the narrative?', 'Shiloh was holier than Gilgal', 'It marked the transition from conquest camp to settled worship center in the land', 'Shiloh was in the center of all twelve tribes'' territories', 'The ark commanded them to go to Shiloh', 'a', 'Joshua 18:1 — The congregation assembled at Shiloh to set up the tabernacle once "the land was subdued before them," marking the shift from military campaign headquarters at Gilgal to a permanent central sanctuary.'),
('Joshua', 18, 'adults', 2, 'What does the phrase "the land was subdued before them" in Joshua 18:1 indicate about the state of the conquest at this point?', 'Every Canaanite had been completely eliminated', 'The major military resistance had been overcome, though pockets remained', 'All seven nations had been utterly destroyed', 'God declared the conquest finished and Israel at rest', 'a', 'Joshua 18:1 — "And the land was subdued before them" — this indicates sufficient military dominance for settlement to proceed, while the subsequent narrative (ch. 18-19) acknowledges remaining Canaanites in some areas.'),
('Joshua', 18, 'adults', 3, 'What was the format of the land survey Joshua ordered — how was the description to be written?', 'As a map drawn on parchment', 'Described in a book in seven parts according to cities', 'Measured in cubits and recorded by tribe', 'Drawn as a diagram of borders only', 'a', 'Joshua 18:9 — "And the men went and passed through the land, and described it by cities into seven parts in a book, and came again to Joshua to the host at Shiloh."'),
('Joshua', 18, 'adults', 4, 'What was the northern border of Benjamin''s allotment and what major city did it touch?', 'The Jordan to the sea of Chinneroth', 'From Jordan to Beth-el, then to Luz and Ataroth-addar', 'The Wadi Qelt to the Mediterranean', 'From Jericho to Gibeon and then to Ekron', 'a', 'Joshua 18:12-13 — "And their border on the north side was from Jordan; and the border went up to the side of Jericho on the north side, and went up through the mountains westward... over from thence toward Luz, to the side of Luz, which is Beth-el, southward."'),
('Joshua', 18, 'adults', 5, 'How did Benjamin''s position between Judah and Ephraim foreshadow the later political tensions in Israelite history?', 'Benjamin always sided with Judah against Ephraim', 'Benjamin''s central location made it a flashpoint between the northern and southern kingdoms', 'The territory was too small to matter politically', 'Benjamin''s capital Jerusalem unified the kingdoms permanently', 'a', 'Benjamin''s location between Judah (south) and Ephraim (north) placed it at the fault line of the later divided kingdom. Jerusalem (on the Benjamin-Judah border) became the contested capital, and Benjamin''s loyalty to the house of David (1 Kings 12:21) was crucial to the southern kingdom.'),
('Joshua', 18, 'adults', 6, 'Which important city on Benjamin''s southern border would later become Israel''s capital under David?', 'Hebron', 'Gibeon', 'Jerusalem (Jebus)', 'Bethlehem', 'a', 'Joshua 18:28 — "And Zelah, Eleph, and Jebusi, which is Jerusalem, Gibeath, and Kirjath; fourteen cities with their villages. This is the inheritance of the children of Benjamin."'),
('Joshua', 18, 'adults', 7, 'What does Joshua''s rebuke of the seven slack tribes in 18:3 reveal about the tension between divine promise and human responsibility?', 'God had already given the land so Israel did not need to act', 'God''s gift of the land did not nullify Israel''s obligation to actively claim it through obedience', 'Joshua was impatient but God was not concerned', 'The slackness was caused by the Canaanites'' military strength', 'a', 'Joshua 18:3 — "How long are ye slack to go to possess the land, which the LORD God of your fathers hath given you?" — Though God had given the land, Israel was responsible for taking possession; divine promise does not eliminate human responsibility.'),
('Joshua', 18, 'adults', 8, 'What was the role of the lot-casting before the LORD at Shiloh, theologically?', 'It allowed the strongest tribes to choose the best land', 'It removed human favoritism and acknowledged God as the true distributor of inheritance', 'It was a random process with no spiritual significance', 'It was used only because Joshua could not decide fairly', 'a', 'Joshua 18:6, 8, 10 — The repeated emphasis on casting lots "before the LORD" indicates God was understood as the divine landlord distributing his land to Israel, making the allocation sacred rather than political.');

-- ═══ Joshua Chapter 19 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Joshua', 19, 'kids', 1, 'Which tribe received land within the territory already given to Judah?', 'Benjamin', 'Simeon', 'Dan', 'Asher', 'a', 'Joshua 19:1 — "And the second lot came forth to Simeon, even for the tribe of the children of Simeon according to their families: and their inheritance was within the inheritance of the children of Judah."'),
('Joshua', 19, 'kids', 2, 'What city did Joshua himself receive as his personal inheritance at the end of the distribution?', 'Shiloh', 'Hebron', 'Timnath-serah', 'Beth-el', 'a', 'Joshua 19:50 — "According to the word of the LORD they gave him the city which he asked, even Timnath-serah in mount Ephraim."'),
('Joshua', 19, 'kids', 3, 'What famous tribe had trouble keeping their territory and later moved to a new location in the north?', 'Ephraim', 'Dan', 'Manasseh', 'Issachar', 'a', 'Joshua 19:47 — "And the coast of the children of Dan went out too little for them: therefore the children of Dan went up to fight against Leshem... and called Leshem, Dan."'),
-- Teens
('Joshua', 19, 'teens', 1, 'Why did Simeon receive an inheritance inside Judah''s territory rather than a separate portion?', 'Simeon was too small and Judah''s part was too large for them', 'Simeon had refused their own lot', 'The land east of Jordan was set aside for Simeon', 'Joshua made an error in the lot casting', 'a', 'Joshua 19:9 — "Out of the portion of the children of Judah was the inheritance of the children of Simeon: for the part of the children of Judah was too much for them: therefore the children of Simeon had their inheritance within the inheritance of them."'),
('Joshua', 19, 'teens', 2, 'What was the inheritance of the tribe of Zebulun''s boundary on the south according to chapter 19?', 'The Sea of Galilee', 'The Kishon River valley', 'Toward the south side: Sarid', 'The valley of Jezreel', 'a', 'Joshua 19:10 — "And the third lot came up for the children of Zebulun according to their families... and the border of their inheritance was unto Sarid."'),
('Joshua', 19, 'teens', 3, 'What was the city that became the inheritance of the tribe of Naphtali''s fortified cities, listed first in its catalog?', 'Hazor', 'Kedesh', 'Iron', 'Migdal-el', 'a', 'Joshua 19:36-37 — "And Adamah, and Ramah, and Hazor, And Kedesh... nineteen cities with their villages." Hazor appears prominently as it was the major northern city.'),
('Joshua', 19, 'teens', 4, 'What city did the children of Dan rename after capturing it from the Sidonians?', 'Leshem renamed Dan', 'Laish renamed Sidon', 'Ekron renamed Timnath', 'Zorah renamed Eshtaol', 'a', 'Joshua 19:47 — "And the coast of the children of Dan went out too little for them: therefore the children of Dan went up to fight against Leshem, and took it... and called Leshem, Dan, after the name of Dan their father."'),
('Joshua', 19, 'teens', 5, 'On what mountain was Joshua''s personal inheritance city, Timnath-serah, located?', 'Mount Tabor', 'Mount Carmel', 'Mount Ephraim', 'Mount Zion', 'a', 'Joshua 19:50 — "According to the word of the LORD they gave him the city which he asked, even Timnath-serah in mount Ephraim: and he built the city, and dwelt therein."'),
-- Adults
('Joshua', 19, 'adults', 1, 'What does Simeon''s inheritance being embedded within Judah''s territory fulfill regarding Jacob''s prophecy in Genesis 49?', 'Jacob promised Simeon special honor within Judah', 'Jacob prophesied that Simeon and Levi would be scattered in Israel for their violence at Shechem', 'Simeon was too weak to fight and needed Judah''s protection', 'God combined Simeon with Judah to make a stronger tribe', 'a', 'Genesis 49:7 — "I will divide them in Jacob, and scatter them in Israel" — Jacob''s curse on Simeon for the Shechem massacre (Genesis 34) is fulfilled by Simeon having no contiguous territory but being scattered within Judah.'),
('Joshua', 19, 'adults', 2, 'Which of Issachar''s cities would later become famous as the site of Deborah and Barak''s victory over Sisera, and appears in chapter 19?', 'Megiddo', 'Jezreel', 'Chesulloth', 'Shunem', 'a', 'Joshua 19:18 — "And their border was toward Jezreel" — the valley of Jezreel and its cities in Issachar''s territory would become the staging ground for the battle of Judges 4-5.'),
('Joshua', 19, 'adults', 3, 'What does the phrase "according to the word of the LORD" regarding Joshua''s personal inheritance at Timnath-serah suggest?', 'Joshua chose his city randomly', 'A divine directive specified Joshua''s personal inheritance, showing he was equally honored by God', 'Only leaders received personal inheritances by divine command', 'Joshua was given extra land as payment for military service', 'a', 'Joshua 19:50 — "According to the word of the LORD they gave him the city which he asked, even Timnath-serah" — this confirms Joshua''s inheritance was divinely sanctioned, honoring him equally as Caleb had been honored in chapter 14.'),
('Joshua', 19, 'adults', 4, 'What geographic challenge faced the tribe of Dan that led to their northern migration, and what does this reflect about tribal territories?', 'Dan was given only desert land with no water', 'Dan''s territory was too small and pressed by Amorites, forcing them to seek land elsewhere', 'Dan refused their allotted territory as undesirable', 'Philistine pressure made Dan''s territory impossible to hold', 'a', 'Joshua 19:47 — "And the coast of the children of Dan went out too little for them" — combined with Judges 1:34 which notes the Amorites forced Dan into the hill country, the tribe''s northern migration reflects both geographic pressure and failure to hold the assigned territory.'),
('Joshua', 19, 'adults', 5, 'Where does Joshua 19:51 state the allotments were completed, and who is specifically named as presiding over the final lots?', 'At Gilgal, by Joshua alone', 'At the door of the tabernacle at Shiloh, by Eleazar, Joshua, and the heads of the fathers of the tribes', 'At Mount Ebal, by the Levitical priests', 'In the city of Shechem before the ark', 'a', 'Joshua 19:51 — "These are the inheritances, which Eleazar the priest, and Joshua the son of Nun, and the heads of the fathers of the tribes of the children of Israel, divided for an inheritance by lot in Shiloh before the LORD, at the door of the tabernacle of the congregation."'),
('Joshua', 19, 'adults', 6, 'What does the fact that Joshua received his inheritance last, after all other tribes had been provided for, reveal about his character?', 'Joshua had no interest in land as a reward', 'He served others first before claiming his own portion, modeling servant leadership', 'The lots were designed so the leader always received the final portion', 'Joshua''s inheritance was the least desirable of all allotments', 'a', 'Joshua 19:49-50 — Joshua asked for and received his city only after the whole land had been divided for all the tribes, paralleling Moses''s selfless leadership and modeling the principle of serving others before oneself.'),
('Joshua', 19, 'adults', 7, 'Which tribe''s territory in chapter 19 encompassed the future site of Nazareth, where Jesus was raised?', 'Zebulun', 'Issachar', 'Naphtali', 'Asher', 'a', 'Joshua 19:15 — Zebulun''s territory included the lower Galilee region; Nazareth is located in the hill country of Zebulun. Isaiah 9:1 specifically names Zebulun and Naphtali as the regions to be honored, fulfilled in Matthew 4:13-16.'),
('Joshua', 19, 'adults', 8, 'How many tribes'' allotments are recorded in Joshua 19, and what does this chapter''s closure statement in verse 51 accomplish narratively?', 'Five tribes, and it begins the cities of refuge section', 'Six tribes (Simeon through Dan), and it formally concludes the entire tribal distribution narrative', 'Seven tribes, and it transitions to Joshua''s farewell', 'Four tribes, and it summarizes all twelve allotments', 'a', 'Joshua 19 records six allotments (Simeon, Zebulun, Issachar, Asher, Naphtali, Dan) plus Joshua''s personal inheritance, and verse 51 formally closes the entire land distribution: "So they made an end of dividing the country."');

-- ═══ Joshua Chapter 20 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Joshua', 20, 'kids', 1, 'What were the special cities God commanded Joshua to set up to protect people who accidentally killed someone?', 'Cities of Levi', 'Cities of refuge', 'Holy cities', 'Cities of safety', 'a', 'Joshua 20:2 — "Speak to the children of Israel, saying, Appoint out for you cities of refuge, whereof I spake unto you by the hand of Moses."'),
('Joshua', 20, 'kids', 2, 'How many cities of refuge were appointed in total across all of Israel?', 'Three cities', 'Six cities', 'Twelve cities', 'Ten cities', 'a', 'Joshua 20:7-8 lists three cities west of Jordan (Kedesh, Shechem, Hebron) and three east (Bezer, Ramoth, Golan), totaling six cities of refuge.'),
('Joshua', 20, 'kids', 3, 'What city of refuge was located in the hill country of Judah?', 'Kedesh', 'Shechem', 'Hebron', 'Golan', 'a', 'Joshua 20:7 — "And they appointed Kedesh in Galilee in mount Naphtali, and Shechem in mount Ephraim, and Kirjath-arba, which is Hebron, in the mountain of Judah."'),
-- Teens
('Joshua', 20, 'teens', 1, 'Who could flee to a city of refuge according to Joshua 20, and for what specific type of killing?', 'Any Israelite who feared an enemy', 'The slayer that killeth any person unawares and unwittingly', 'Only priests who had sinned accidentally', 'Any foreigner who was threatened by Israel', 'a', 'Joshua 20:3 — "That the slayer that killeth any person unawares and unwittingly may flee thither: and they shall be your refuge from the avenger of blood."'),
('Joshua', 20, 'teens', 2, 'What was the procedure for someone seeking refuge in a city of refuge?', 'Pray at the city gate and wait for a priest', 'Stand at the entry of the gate of the city and declare his cause in the ears of the elders', 'Bring two witnesses and present them to the high priest', 'Pay a ransom to the elders of the city', 'a', 'Joshua 20:4 — "And when he that doth flee unto one of those cities shall stand at the entering of the gate of the city, and shall declare his cause in the ears of the elders of that city."'),
('Joshua', 20, 'teens', 3, 'What would happen to the person in the city of refuge when the high priest died?', 'He would be judged again by the elders', 'He could return to his own city and home safely', 'He had to stay in the city for the rest of his life', 'The avenger of blood could no longer pursue him anywhere', 'a', 'Joshua 20:6 — "And he shall dwell in that city, until he stand before the congregation for judgment, and until the death of the high priest that shall be in those days: then shall the slayer return, and come unto his own city."'),
('Joshua', 20, 'teens', 4, 'Which city of refuge was located in Galilee in the mountain of Naphtali?', 'Shechem', 'Ramoth in Gilead', 'Kedesh', 'Golan', 'a', 'Joshua 20:7 — "And they appointed Kedesh in Galilee in mount Naphtali, and Shechem in mount Ephraim, and Kirjath-arba, which is Hebron, in the mountain of Judah."'),
('Joshua', 20, 'teens', 5, 'Which city of refuge east of the Jordan was in Manasseh territory?', 'Bezer', 'Ramoth in Gilead', 'Golan in Bashan', 'Shechem', 'a', 'Joshua 20:8 — "And on the other side Jordan by Jericho eastward, they assigned Bezer in the wilderness upon the plain out of the tribe of Reuben, and Ramoth in Gilead out of the tribe of Gad, and Golan in Bashan out of the tribe of Manasseh."'),
-- Adults
('Joshua', 20, 'adults', 1, 'The cities of refuge system commanded in Joshua 20 fulfills instructions given where earlier in the Torah?', 'Leviticus 25 and Deuteronomy 4', 'Numbers 35 and Deuteronomy 19', 'Exodus 21 and Leviticus 24', 'Genesis 9 and Exodus 22', 'a', 'Joshua 20:2 — "Appoint out for you cities of refuge, whereof I spake unto you by the hand of Moses" — Numbers 35:6-15 and Deuteronomy 19:1-13 provide the detailed legislation Joshua is here implementing.'),
('Joshua', 20, 'adults', 2, 'What legal distinction does the system of cities of refuge make that is theologically significant for justice?', 'It distinguishes between rich and poor defendants', 'It distinguishes between intentional murder and accidental manslaughter, protecting the innocent from vigilante vengeance', 'It provides immunity from all crimes for Levites', 'It separates civil disputes from religious ones', 'a', 'Joshua 20:3 — "That the slayer that killeth any person unawares and unwittingly may flee thither" — the system reflects the Torah''s careful distinction between premeditated murder (deserving death) and accidental killing (deserving protection).'),
('Joshua', 20, 'adults', 3, 'Why was it important that the six cities be distributed on both sides of the Jordan, with three on each side?', 'To reflect the equal status of eastern and western tribes', 'To ensure accessibility for any Israelite throughout the entire land without requiring a long journey', 'Because the Torah specified exactly three on each side', 'To honor the three patriarchs Abraham, Isaac, and Jacob', 'a', 'The geographic distribution (Kedesh in the north, Shechem in the center, Hebron in the south on the west; Golan north, Ramoth center, Bezer south on the east) ensured a person fleeing from anywhere in Israel could reach a city of refuge without excessive travel.'),
('Joshua', 20, 'adults', 4, 'What role do the elders of the city of refuge play in the process described in Joshua 20:4-5?', 'They judge whether the killing was intentional', 'They receive the fleeing person into the city and protect him from the avenger', 'They consult the high priest before deciding', 'They hold a trial with twelve witnesses', 'a', 'Joshua 20:4-5 — "They shall take him into the city unto them, and give him a place, that he may dwell among them. And if the avenger of blood pursue after him, then they shall not deliver the slayer up into his hand."'),
('Joshua', 20, 'adults', 5, 'What theological truth does the death of the high priest serve in releasing the manslayer from the city of refuge?', 'The high priest''s death was a punishment for Israel''s sins', 'The high priest''s death functioned as an atoning death that cleansed the blood guilt and allowed the innocent killer to return home', 'It was an arbitrary time limit set by tradition', 'The new high priest needed to reassess all pending cases', 'a', 'Numbers 35:25, 28 and Joshua 20:6 — "Until the death of the high priest that shall be in those days" — ancient Jewish interpretation held that the high priest''s death served an atoning function; typologically, Christ as our High Priest has died so we are released from condemnation.'),
('Joshua', 20, 'adults', 6, 'The cities of refuge were all Levitical cities — what is the significance of this connection to the priestly tribe?', 'The Levites were the only ones trusted to administer justice fairly', 'It connected the place of protection from blood guilt with the place of worship and priestly ministry', 'Levitical cities were the safest because they were fortified', 'God wanted the Levites to have more population in their cities', 'a', 'Joshua 21:13, 21, 27, 32, 36, 38 later confirms all six cities of refuge were among the Levitical cities, linking physical asylum with the presence of priestly ministry — the same place where atonement was sought was also where refuge was found.'),
('Joshua', 20, 'adults', 7, 'What does the provision that strangers (foreigners) could also flee to cities of refuge reveal about Israel''s legal system?', 'Israel had no distinction between citizens and foreigners in criminal matters', 'The protection of law extended even to resident aliens, reflecting God''s justice as impartial', 'Foreigners paid a higher tribute for protection', 'Strangers were only protected if they converted to Judaism', 'a', 'Joshua 20:9 — "These were the cities appointed for all the children of Israel, and for the stranger that sojourneth among them" — the inclusion of sojourning foreigners reflects Leviticus 24:22, "Ye shall have one manner of law, as well for the stranger, as for one of your own country."'),
('Joshua', 20, 'adults', 8, 'How do the six cities of refuge serve as a type or foreshadowing of Christ in Christian theological interpretation?', 'They represent the six days of creation that God will restore', 'As the only place of safety from the avenger, they typify Christ as the believer''s refuge from the condemnation of the law', 'They represent the six covenants God made with Israel', 'They foreshadow the six seals of Revelation', 'a', 'The cities of refuge are a recognized type of Christ: as the manslayer who fled received complete protection by entering the city, so the sinner who flees to Christ is sheltered from condemnation (Romans 8:1 — "There is therefore now no condemnation to them which are in Christ Jesus")');
